# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, session, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
import sqlite3

app = Flask(__name__)
app.secret_key = 'your-secret-key'

def get_db():
    conn = sqlite3.connect('users.db')
    conn.row_factory = sqlite3.Row
    return conn

@app.route('/api/profile', methods=['POST'])
def update_profile():
    if 'user_id' not in session:
        return jsonify({'error': 'Unauthorized'}), 401
    
    user_id = session['user_id']
    data = request.get_json()
    
    conn = get_db()
    user = conn.execute('SELECT * FROM users WHERE id = ?', (user_id,)).fetchone()
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    # Update email if provided
    if 'email' in data:
        conn.execute('UPDATE users SET email = ? WHERE id = ?', (data['email'], user_id))
    
    # Update password if provided
    if 'password' in data:
        if not check_password_hash(user['password_hash'], data.get('old_password', '')):
            return jsonify({'error': 'Current password is incorrect'}), 400
        conn.execute('UPDATE users SET password_hash = ? WHERE id = ?', 
                    (generate_password_hash(data['password']), user_id))
    
    # Update 2FA settings if provided
    if 'two_factor_enabled' in data:
        conn.execute('UPDATE users SET two_factor_enabled = ? WHERE id = ?', 
                    (data['two_factor_enabled'], user_id))
    
    conn.commit()
    conn.close()
    
    return jsonify({'message': 'Profile updated successfully'}), 200